  1	import * as React from 'react';
  2	import { kialiStyle } from 'styles/StyleUtils';
  3	import { Button, Tooltip } from '@patternfly/react-core';
  4	import { config } from '../../config';
  5	import { KialiIcon } from '../../config/KialiIcon';
  6	import { DurationInSeconds, guardTimeRange, TimeRange } from '../../types/Common';
  7	import { getName, getRefreshIntervalName } from '../../utils/RateIntervals';
  8	import { KialiAppState } from '../../store/Store';
  9	import { durationSelector, refreshIntervalSelector, timeRangeSelector } from '../../store/Selectors';
 10	import { connect } from 'react-redux';
 11	import { HistoryManager, location } from '../../app/History';
 12	import { KialiDispatch } from '../../types/Redux';
 13	import { bindActionCreators } from 'redux';
 14	import { UserSettingsActions } from '../../actions/UserSettingsActions';
 15	import { t } from 'utils/I18nUtils';
 16	
 17	type ReduxStateProps = {
 18	  duration: DurationInSeconds;
 19	  refreshInterval: number;
 20	  timeRange: TimeRange;
 21	};
 22	
 23	type ReduxDispatchProps = {
 24	  setDuration: (duration: DurationInSeconds) => void;
 25	};
 26	
 27	type Props = ReduxStateProps &
 28	  ReduxDispatchProps & {
 29	    id?: string;
 30	    isDuration?: boolean;
 31	    onClick?: () => void;
 32	    setDuration: (duration: DurationInSeconds) => void;
 33	  };
 34	
 35	const infoStyle = kialiStyle({
 36	  margin: '0 0.25rem 0.125rem 0.25rem'
 37	});
 38	
 39	class TimeDurationIndicatorComponent extends React.PureComponent<Props> {
 40	  constructor(props: Props) {
 41	    super(props);
 42	
 43	    // This is needed to initialise the component using the parameters in the URL.
 44	    // If we don't set the state, we lost the value if we click in other tabs and go back
 45	    const urlParams = new URLSearchParams(location.getSearch());
 46	    const urlDuration = HistoryManager.getDuration(urlParams);
 47	
 48	    if (urlDuration !== undefined && urlDuration !== props.duration) {
 49	      props.setDuration(urlDuration);
 50	    }
 51	  }
 52	
 53	  timeDurationIndicator = (): React.ReactNode => {
 54	    if (this.props.isDuration) {
 55	      return getName(this.props.duration);
 56	    } else {
 57	      return guardTimeRange(this.props.timeRange, getName, () => t('custom'));
 58	    }
 59	  };
 60	
 61	  timeDurationDetailLabel = (): React.ReactNode => {
 62	    return this.props.isDuration ? t('Current duration') : t('Current time range');
 63	  };
 64	
 65	  timeDurationDetail = (): string => {
 66	    if (this.props.isDuration) {
 67	      return t('Last {{duration}}', { duration: getName(this.props.duration) });
 68	    } else {
 69	      return guardTimeRange(
 70	        this.props.timeRange,
 71	        d => t('Last {{duration}}', { duration: getName(d) }),
 72	        b => {
 73	          const oldDate = new Date(b.from!).toLocaleString();
 74	          const newDate = b.to ? new Date(b.to).toLocaleString() : t('now');
 75	          return t('{{oldDate}} to {{newDate}}', { oldDate, newDate });
 76	        }
 77	      );
 78	    }
 79	  };
 80	
 81	  render(): React.ReactNode {
 82	    return (
 83	      <Tooltip
 84	        trigger={'mouseenter'}
 85	        isContentLeftAligned={true}
 86	        maxWidth={'50em'}
 87	        content={
 88	          <>
 89	            <p>{t('Select the time range of shown data, and the refresh interval.')}</p>
 90	            <p style={{ whiteSpace: 'nowrap' }}>
 91	              {this.timeDurationDetailLabel()}: {this.timeDurationDetail()}
 92	              <br />
 93	              {t('Current refresh interval: {{refreshInterval}}', {
 94	                refreshInterval: t(config.toolbar.refreshInterval[this.props.refreshInterval])
 95	              })}
 96	            </p>
 97	          </>
 98	        }
 99	      >
100	        <Button id={this.props.id} variant="link" isInline={true} onClick={this.props.onClick}>
101	          <KialiIcon.Clock className={infoStyle} />
102	          {this.timeDurationIndicator()}, {getRefreshIntervalName(this.props.refreshInterval)}
103	        </Button>
104	      </Tooltip>
105	    );
106	  }
107	}
108	
109	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
110	  duration: durationSelector(state),
111	  timeRange: timeRangeSelector(state),
112	  refreshInterval: refreshIntervalSelector(state)
113	});
114	
115	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
116	  return {
117	    setDuration: bindActionCreators(UserSettingsActions.setDuration, dispatch)
118	  };
119	};
120	
121	export const TimeDurationIndicator = connect(mapStateToProps, mapDispatchToProps)(TimeDurationIndicatorComponent);

